const items = $input.all();

for (let item of items) {
  const attachments = item.json.attachments || [];
  let binaryProperties = [];

  for (let i = 0; i < attachments.length; i++) {
    const att = attachments[i];
    if (att.url) {
      try {
        const response = await this.helpers.request({
          url: att.url,
          method: 'GET',
          encoding: null,
          resolveWithFullResponse: true
        });

        const propName = `attachment_${i}`;
        binaryProperties.push(propName);

        if (!item.binary) item.binary = {};

        item.binary[propName] = {
          data: response.body.toString('base64'),
          mimeType: att.type || 'application/octet-stream',
          fileName: att.name || `file_${i}`
        };
      } catch (err) {
        console.log('Error descargando adjunto:', err.message);
      }
    }
  }
  item.json.binaryAttachmentsList = binaryProperties.join(',');
}

return items;
